  1	import * as React from 'react';
  2	import cx from 'classnames';
  3	import {
  4	  Text,
  5	  TextInputTypes,
  6	  FormGroup,
  7	  ClipboardCopy,
  8	  InputGroup,
  9	  ExpandableSection,
 10	  Button,
 11	  Tooltip,
 12	  InputGroupItem,
 13	  FormHelperText,
 14	  HelperText,
 15	  HelperTextItem,
 16	  FormSection,
 17	} from '@patternfly/react-core';
 18	import { HelpIcon } from '@patternfly/react-icons/dist/esm/icons/help-icon';
 19	import { FormikValues, useFormikContext } from 'formik';
 20	import * as fuzzy from 'fuzzysearch';
 21	import { Base64 } from 'js-base64';
 22	import * as _ from 'lodash';
 23	import { Trans, useTranslation } from 'react-i18next';
 24	
 25	import PermissionsSection from './PermissionsSection';
 26	import { ConfigMapKind } from './types';
 27	import {
 28	  K8sResourceCommon,
 29	  K8sResourceKind,
 30	  useActiveNamespace,
 31	  useK8sWatchResource,
 32	} from '@openshift-console/dynamic-plugin-sdk';
 33	import { SecretModel } from '../../models';
 34	import { GitProvider } from '../utils/repository-utils';
 35	import InputField from '../pipelines-details/multi-column-field/InputField';
 36	import RadioGroupField from '../pipeline-builder/RadioGroupField';
 37	import { ExternalLink } from '../utils/link';
 38	import { AccessTokenDocLinks, WebhookDocLinks } from './const';
 39	import { generateSecret } from './utils';
 40	import ResourceDropdown from '../common/ResourceDropdown';
 41	
 42	import './RepositoryForm.scss';
 43	
 44	type WebhoookSectionProps = {
 45	  pac: ConfigMapKind;
 46	  formContextField?: string;
 47	};
 48	
 49	const WebhookSection: React.FC<WebhoookSectionProps> = ({
 50	  pac,
 51	  formContextField,
 52	}) => {
 53	  const [namespace] = useActiveNamespace();
 54	  const { values, setFieldValue, setFieldTouched } =
 55	    useFormikContext<FormikValues>();
 56	  const fieldPrefix = formContextField ? `${formContextField}.` : '';
 57	  const { gitProvider, webhook } = _.get(values, formContextField) || values;
 58	  const [controllerUrl, setControllerUrl] = React.useState('');
 59	  const [webhookSecret, setWebhookSecret] = React.useState('');
 60	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 61	
 62	  React.useEffect(() => {
 63	    const ctlUrl = pac?.data?.['controller-url'];
 64	    if (ctlUrl) {
 65	      setControllerUrl(ctlUrl);
 66	      setFieldValue(`${fieldPrefix}webhook.url`, ctlUrl);
 67	    }
 68	  }, [fieldPrefix, pac, setFieldValue]);
 69	  const autocompleteFilter = (text: string, item: any): boolean =>
 70	    fuzzy(text, item?.props?.name);
 71	  const secretResource = {
 72	    isList: true,
 73	    kind: SecretModel.kind,
 74	    namespace: namespace,
 75	    prop: SecretModel.id,
 76	  };
 77	
 78	  const [secrets, loaded, loadError] =
 79	    useK8sWatchResource<K8sResourceCommon[]>(secretResource);
 80	  const generateWebhookSecret = () => {
 81	    setWebhookSecret(generateSecret());
 82	  };
 83	
 84	  const getPermssionSectionHeading = (git: GitProvider) => {
 85	    switch (git) {
 86	      case GitProvider.GITHUB:
 87	        return t('See GitHub events');
 88	      case GitProvider.GITLAB:
 89	        return t('See Gitlab events');
 90	      case GitProvider.BITBUCKET:
 91	        return t('See BitBucket events');
 92	      default:
 93	        return t('See Git events');
 94	    }
 95	  };
 96	
 97	  const HelpText = (): React.ReactElement => {
 98	    let helpText: React.ReactNode;
 99	    switch (gitProvider) {
100	      case GitProvider.GITHUB:
101	        helpText = (
102	          <Trans t={t} ns="plugin__pipelines-console-plugin">
103	            Use your GitHub Personal token. Use this{' '}
104	            <a
105	              href={AccessTokenDocLinks[GitProvider.GITHUB]}
106	              target="_blank"
107	              rel="noopener noreferrer"
108	            >
109	              link
110	            </a>{' '}
111	            to create a <b>classic</b> token with <b>repo</b> &{' '}
112	            <b>admin:repo_hook</b> scopes and give your token an expiration, i.e
113	            30d.
114	          </Trans>
115	        );
116	        break;
117	
118	      case GitProvider.GITLAB:
119	        helpText = (
120	          <Trans t={t} ns="plugin__pipelines-console-plugin">
121	            Use your Gitlab Personal access token. Use this{' '}
122	            <a
123	              href={AccessTokenDocLinks[GitProvider.GITLAB]}
124	              target="_blank"
125	              rel="noopener noreferrer"
126	            >
127	              link
128	            </a>{' '}
129	            to create a token with <b>api</b> scope. Select the role as{' '}
130	            <b>Maintainer/Owner</b>. Give your token an expiration i.e 30d.
131	          </Trans>
132	        );
133	        break;
134	
135	      case GitProvider.BITBUCKET:
136	        helpText = (
137	          <Trans t={t} ns="plugin__pipelines-console-plugin">
138	            Use your Bitbucket App password. Use this{' '}
139	            <a
140	              href={AccessTokenDocLinks[GitProvider.BITBUCKET]}
141	              target="_blank"
142	              rel="noopener noreferrer"
143	            >
144	              link
145	            </a>{' '}
146	            to create a token with <b>Read and Write </b>scopes in{' '}
147	            <b>
148	              Account, Workspace membership, Projects, Issues, Pull requests and
149	              Webhooks
150	            </b>
151	            .
152	          </Trans>
153	        );
154	        break;
155	
156	      default:
157	        helpText = (
158	          <Trans t={t} ns="plugin__pipelines-console-plugin">
159	            Use your Git Personal token. Create a token with repo, public_repo &
160	            admin:repo_hook scopes and give your token an expiration, i.e 30d.
161	          </Trans>
162	        );
163	    }
164	
165	    return <div data-test={`${values.gitProvider}-helptext`}>{helpText}</div>;
166	  };
167	
168	  return (
169	    <FormSection>
170	      {gitProvider && gitProvider === GitProvider.BITBUCKET ? (
171	        <InputField
172	          label={t('Bitbucket username')}
173	          name={`${fieldPrefix}webhook.user`}
174	          type={TextInputTypes.text}
175	          required
176	        />
177	      ) : null}
178	      <RadioGroupField
179	        name={`${fieldPrefix}webhook.method`}
180	        label={t('Secret')}
181	        labelIcon={
182	          <Tooltip
183	            position="right"
184	            content={
185	              <p>
186	                {t(
187	                  'The secret is required to set the Build status and to attach the webhook to the Git repository.',
188	                )}
189	              </p>
190	            }
191	          >
192	            <HelpIcon />
193	          </Tooltip>
194	        }
195	        required
196	        options={[
197	          {
198	            value: 'token',
199	            label: t('Git access token'),
200	            activeChildren: (
201	              <InputField
202	                name={`${fieldPrefix}webhook.token`}
203	                type={TextInputTypes.text}
204	                helpText={<HelpText />}
205	                required
206	              />
207	            ),
208	          },
209	          {
210	            value: 'secret',
211	            label: t('Git access token secret'),
212	
213	            activeChildren: (
214	              <ResourceDropdown
215	                helpText={t(
216	                  'Secret with the Git access token for pulling pipeline and tasks from your Git repository.',
217	                )}
218	                name={`${fieldPrefix}webhook.secretRef`}
219	                id={`${fieldPrefix}webhook.secretRef`}
220	                selectedKey={`${fieldPrefix}webhook.secretRef`}
221	                resources={[
222	                  {
223	                    kind: SecretModel.kind,
224	                    loaded,
225	                    loadError,
226	                    data: secrets as K8sResourceKind[],
227	                  },
228	                ]}
229	                loaded={loaded}
230	                loadError={loadError}
231	                dataSelector={['metadata', 'name']}
232	                placeholder={t('Select a secret')}
233	                autocompleteFilter={autocompleteFilter}
234	                dropDownClassName={cx({ 'dropdown--full-width': true })}
235	                buttonClassName={cx({ 'dropdown--full-width': true })}
236	                dropDownContentClassName="pipelines-console-plugin__flexBetween"
237	                fullWidth
238	                showBadge
239	                onChange={(k, v, res) => {
240	                  if (res && res.data) {
241	                    setFieldValue(`${fieldPrefix}webhook.secretObj`, res);
242	                    setFieldValue(`${fieldPrefix}webhook.secretRef`, k);
243	                    const secret = res?.data['webhook.secret'];
244	                    if (secret) {
245	                      try {
246	                        setWebhookSecret(Base64.decode(secret));
247	                      } catch (err) {
248	                        console.warn(
249	                          'Invalid Base64 string in webhook.secret:',
250	                          secret,
251	                          err,
252	                        );
253	                      }
254	                    }
255	                    setTimeout(() => {
256	                      setFieldTouched(`${fieldPrefix}webhook.secretRef`, true);
257	                      setFieldTouched(`${fieldPrefix}webhook.secretObj`, true);
258	                    }, 0);
259	                  }
260	                }}
261	              />
262	            ),
263	          },
264	        ]}
265	      />
266	      {webhook?.url && (
267	        <FormGroup fieldId="test" label={t('Webhook URL')}>
268	          <ClipboardCopy
269	            isReadOnly
270	            name={`${fieldPrefix}webhook.url`}
271	            hoverTip="Copy"
272	            clickTip="Copied"
273	            style={{ flex: '1' }}
274	          >
275	            {controllerUrl}
276	          </ClipboardCopy>
277	
278	          <FormHelperText>
279	            <HelperText>
280	              <HelperTextItem>
281	                {t(
282	                  'We have detected a URL that can be used to configure the webhook. It will be created and attached to the Git repository.',
283	                )}
284	              </HelperTextItem>
285	            </HelperText>
286	          </FormHelperText>
287	        </FormGroup>
288	      )}
289	
290	      {gitProvider && gitProvider !== GitProvider.BITBUCKET ? (
291	        <FormGroup
292	          fieldId={'webhook-secret-clipboard'}
293	          label={t('Webhook secret')}
294	        >
295	          <InputGroup style={{ display: 'flex' }}>
296	            <InputGroupItem>
297	              <ClipboardCopy
298	                name={`${fieldPrefix}webhook.secret`}
299	                hoverTip="Copy"
300	                clickTip="Copied"
301	                style={{ flex: '1' }}
302	                onChange={(_event, v) => {
303	                  setFieldValue(`${fieldPrefix}webhook.secret`, v);
304	                }}
305	              >
306	                {webhookSecret}
307	              </ClipboardCopy>
308	            </InputGroupItem>
309	            <InputGroupItem>
310	              <Button
311	                data-test="generate-secret"
312	                variant="control"
313	                onClick={generateWebhookSecret}
314	              >
315	                {t('Generate')}
316	              </Button>
317	            </InputGroupItem>
318	          </InputGroup>
319	        </FormGroup>
320	      ) : null}
321	
322	      {gitProvider && gitProvider !== GitProvider.UNSURE ? (
323	        <>
324	          <ExpandableSection
325	            toggleText={getPermssionSectionHeading(gitProvider)}
326	          >
327	            <FormGroup
328	              label={t('Events triggering the webhook: ')}
329	              fieldId="repo-permissions"
330	            >
331	              <Text>
332	                <PermissionsSection formContextField={formContextField} />
333	              </Text>
334	            </FormGroup>
335	          </ExpandableSection>
336	
337	          <ExternalLink
338	            text={t('Read more about setting up webhook')}
339	            href={WebhookDocLinks[gitProvider]}
340	          />
341	        </>
342	      ) : null}
343	    </FormSection>
344	  );
345	};
346	
347	export default WebhookSection;

