118	      case GitProvider.GITLAB:
119	        helpText = (
120	          <Trans t={t} ns="plugin__pipelines-console-plugin">
121	            Use your Gitlab Personal access token. Use this{' '}
122	            <a
123	              href={AccessTokenDocLinks[GitProvider.GITLAB]}
124	              target="_blank"
125	              rel="noopener noreferrer"
126	            >
127	              link
128	            </a>{' '}
129	            to create a token with <b>api</b> scope. Select the role as{' '}
